class Solution:
    def dominantIndices(self, nums: 'list[int]') -> int:
        n = len(nums)
        count = 0
        suffix_sum = 0
        suffix_len = 0
        for i in range(n - 1, -1, -1):
            if suffix_len > 0 and nums[i] * suffix_len > suffix_sum:
                count += 1
            suffix_sum += nums[i]
            suffix_len += 1
        return count

