var dominantIndices = function(nums) {
    const n = nums.length;
    let count = 0;
    let suffixSum = 0;
    let suffixLen = 0;
    for (let i = n - 1; i >= 0; i--) {
        if (suffixLen > 0 && nums[i] * suffixLen > suffixSum) {
            count += 1;
        }
        suffixSum += nums[i];
        suffixLen += 1;
    }
    return count;
};
